package ru.tzfviewer;
import java.util.*;
final class PointBudgetAllocator{
 static final class Item{final String id;final long available;final float weight;final boolean visible,active;Item(String id,long available,float weight,boolean visible,boolean active){this.id=id;this.available=Math.max(0,available);this.weight=Math.max(.01f,weight);this.visible=visible;this.active=active;}}
 static Map<String,Integer> allocate(int budget,List<Item> items){LinkedHashMap<String,Integer> out=new LinkedHashMap<>();List<Item> visible=new ArrayList<>();for(Item i:items){out.put(i.id,0);if(i.visible&&i.available>0)visible.add(i);}if(budget<=0||visible.isEmpty())return out;long totalAvailable=0;for(Item i:visible)totalAvailable+=i.available;int target=(int)Math.min((long)budget,totalAvailable),minimum=Math.min(20_000,target/visible.size()),used=0;for(Item i:visible){int n=(int)Math.min(i.available,minimum);out.put(i.id,n);used+=n;}while(used<target){float weights=0;for(Item i:visible)if(out.get(i.id)<i.available)weights+=i.weight*(i.active?1.35f:1f);if(weights==0)break;int before=used;for(Item i:visible){int current=out.get(i.id);if(current>=i.available)continue;int share=Math.max(1,Math.round((target-used)*(i.weight*(i.active?1.35f:1f))/weights));int add=(int)Math.min(Math.min((long)share,i.available-current),target-used);out.put(i.id,current+add);used+=add;if(used==target)break;}if(used==before)break;}return out;}
}
